    /**
     * Convert a Card.ord (as provided by [NoteEditor.performPreview]) into a 0-based index into the
     * previewable cards.
     */
    private fun initialCardIndexFromOrdinal(col: Collection, ordinal: Int): Int {
        val notetype = mEditedNotetype ?: return 0

        if (!notetype.isCloze) {
            val templateCount = notetype.templatesNames.size
            return if (templateCount <= 0) 0 else ordinal.coerceIn(0, templateCount - 1)
        }

        val note = noteFromNoteEditorBundle(col) ?: return 0
        val clozeOrdinals = col.clozeNumbersInNote(note)
        if (clozeOrdinals.isEmpty()) {
            return 0
        }

        // Historically this has been ambiguous: some call sites treat the values as cloze numbers (1-based),
        // others as ordinals (0-based). Prefer an exact match, then fall back.
        val exactIndex = clozeOrdinals.indexOf(ordinal)
        if (exactIndex >= 0) {
            return exactIndex
        }

        val ordPlusOneIndex = clozeOrdinals.indexOf(ordinal + 1)
        return if (ordPlusOneIndex >= 0) ordPlusOneIndex else 0
    }

    private fun noteFromNoteEditorBundle(col: Collection): Note? {
        val notetype = mEditedNotetype ?: return null
        val note = col.newNote(notetype)
        val fieldValues = getBundleEditFields(mNoteEditorBundle)

        var i = 0
        while (i < fieldValues.size && i < note.fields.size) {
            note.setField(i, fieldValues[i])
            i++
        }

        return note
    }
