501→/**
502→ * Returns the list of cloze card ordinals present in this note.
503→ *
504→ * Example: "{{c1::A}} {{c3::B}}" -> [0, 2]
505→ */
506→private fun Note.clozeOrdinalsInFields(): List<Int> {
507→    val ordinals = mutableSetOf<Int>()
508→    for (field in fields) {
509→        for (m in CLOZE_DELETION_REGEX.findAll(field)) {
510→            val clozeNumber = m.groupValues[1].toIntOrNull() ?: continue
511→            if (clozeNumber >= 1) {
512→                ordinals.add(clozeNumber - 1)
513→            }
514→        }
515→    }
516→
517→    // If there are no cloze deletions, allow preview of a single "missing cloze" card (c1).
518→    if (ordinals.isEmpty()) {
519→        return listOf(0)

518→    if (ordinals.isEmpty()) {
519→        return listOf(0)
520→    }
521→
522→    return ordinals.toList().sorted()
523→}
