526→private fun Note.numberOfCardsEphemeral(): Int {
527→    // We can't use note.numberOfCards() as this uses the database value
528→    return when {
529→        this.notetype.isCloze -> this.clozeOrdinalsInFields().size
530→        else -> notetype.templatesNames.size
531→    }
532→}
