package com.ichi2.anki

import android.content.Intent
import com.ichi2.anki.servicelayer.NoteService
import com.ichi2.anki.servicelayer.NoteService.getFieldsAsBundleForPreview
import com.ichi2.utils.KotlinCleanup
import org.hamcrest.CoreMatchers.containsString
import org.hamcrest.CoreMatchers.not
import org.hamcrest.MatcherAssert.assertThat
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner

@RunWith(RobolectricTestRunner::class)
class CardTemplatePreviewerOrdinalRegressionTest : RobolectricTest() {

    @Test
    fun `Note editor preview uses provided ordinal (standard note type)`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "Hello"),
            Field(1, "World")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val model = getCurrentDatabaseModelCopy("Basic (and reversed card)")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, model)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                android.os.Bundle().apply {
                    putBundle("editFields", getFieldsAsBundleForPreview(fields))
                    putLong("did", 1L)
                }
            )
            putExtra("ordinal", 1)
        }

        val previewer = startActivityNormallyOpenCollectionWithIntent(TestCardTemplatePreviewer::class.java, intent)

        assertThat("Front is not displayed", previewer.cardContent, not(containsString("Hello")))
        assertThat("Back is displayed", previewer.cardContent, containsString("World"))
    }

    @Test
    fun `Note editor preview uses provided ordinal (cloze with gaps)`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "{{c1::Hello}} {{c3::World}}"),
            Field(1, "Extra")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val model = getCurrentDatabaseModelCopy("Cloze")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, model)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                android.os.Bundle().apply {
                    putBundle("editFields", getFieldsAsBundleForPreview(fields))
                    putLong("did", 1L)
                }
            )
            // c3 -> ord 2
            putExtra("ordinal", 2)
        }

        val previewer = startActivityNormallyOpenCollectionWithIntent(TestCardTemplatePreviewer::class.java, intent)

        assertThat("Non-deleted cloze text is displayed", previewer.cardContent, containsString("Hello"))
        assertThat("Deleted cloze text is hidden", previewer.cardContent, not(containsString("World")))
    }

    @KotlinCleanup("Override fieldText in constructor and remove text")
    private inner class Field(override val ord: Int, private val text: String) : NoteService.NoteField {
        override val fieldText: String
            get() = text
    }
}
"}

