/**
 * Returns the list of cloze card ordinals present in this note.
 *
 * Example: "{{c1::A}} {{c3::B}}" -> [0, 2]
 */
private fun Note.clozeOrdinalsInFields(): List<Int> {
    val ordinals = mutableSetOf<Int>()
    for (field in fields) {
        for (m in CLOZE_DELETION_REGEX.findAll(field)) {
            val clozeNumber = m.groupValues[1].toIntOrNull() ?: continue
            if (clozeNumber >= 1) {
                ordinals.add(clozeNumber - 1)
            }
        }
    }

    // If there are no cloze deletions, allow preview of a single "missing cloze" card (c1).
    if (ordinals.isEmpty()) {
        return listOf(0)
    }

    return ordinals.toList().sorted()
}

